import React from 'react';
import styled from 'styled-components';

const Container = styled.div`
  padding: 4rem 2rem;
  max-width: 1200px;
  margin: 0 auto;
  background-color: #f9fafb;
  min-height: 100vh;
`;

const Hero = styled.div`
  text-align: center;
  margin-bottom: 4rem;
`;

const HeroTitle = styled.h1`
  font-size: 3rem;
  color: #1a202c;
  font-weight: 700;
  margin-bottom: 1rem;
`;

const HeroSubtitle = styled.h2`
  font-size: 1.35rem;
  color: #475569;
  font-weight: 500;
  max-width: 700px;
  margin: 0 auto;
`;

const Section = styled.section`
  margin-bottom: 4.5rem;
`;

const SectionTitle = styled.h3`
  font-size: 2.1rem;
  color: #1e2937;
  margin-bottom: 1.8rem;
  font-weight: 700;
  position: relative;
  display: inline-block;

  &:after {
    content: '';
    position: absolute;
    bottom: -6px;
    left: 0;
    width: 60px;
    height: 3px;
    background: #667eea;
    border-radius: 2px;
  }
`;

const BioText = styled.p`
  font-size: 1.1rem;
  color: #475569;
  line-height: 1.85;
  margin-bottom: 1.6rem;
  max-width: 780px;
`;

const SkillsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 2.2rem;
`;

const SkillCategory = styled.div`
  background: #ffffff;
  padding: 2rem;
  border-radius: 12px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  border: 1px solid #f1f5f9;
`;

const SkillTitle = styled.h4`
  font-size: 1.35rem;
  color: #1e2937;
  margin-bottom: 1.2rem;
  font-weight: 700;
  display: flex;
  align-items: center;
  gap: 0.6rem;
`;

const SkillList = styled.ul`
  list-style: none;
  padding: 0;
  margin: 0;
`;

const SkillItem = styled.li`
  font-size: 1.05rem;
  color: #334155;
  margin-bottom: 0.75rem;
  padding-left: 1.6rem;
  position: relative;
  line-height: 1.6;

  &:before {
    content: '→';
    color: #667eea;
    position: absolute;
    left: 0;
    font-weight: bold;
  }
`;

const About = () => (
  <Container>
    <Hero>
      <HeroTitle>About Joël Tiogo</HeroTitle>
      <HeroSubtitle>
        Business Development Leader &amp; AI Consultant | MBA in Technology &amp; Sustainability
      </HeroSubtitle>
    </Hero>

    <Section>
      <SectionTitle>Professional Background</SectionTitle>
      <BioText>
        I am a dynamic business development professional and AI consultant with a unique combination of
        entrepreneurial experience, strategic leadership, and deep technical expertise in artificial intelligence.
      </BioText>
      <BioText>
        Holding an MBA in Technology and Sustainability from Frankfurt School of Finance &amp; Management,
        I specialize in bridging cutting-edge technologies with commercial strategy. My work focuses on driving
        sustainable innovation, particularly in the automotive and energy sectors, through digital transformation,
        ESG initiatives, and AI-powered solutions.
      </BioText>
      <BioText>
        With hands-on experience as a former founder &amp; CEO, I bring a practical understanding of scaling
        businesses while leveraging technologies such as computer vision, IoT, and data-driven systems.
        Trilingual in French, English, and German, I have successfully navigated international markets across
        Europe, Africa, and North America, building strong stakeholder relationships and delivering measurable growth.
      </BioText>
    </Section>

    <Section>
      <SectionTitle>Core Expertise</SectionTitle>
      <SkillsGrid>
        <SkillCategory>
          <SkillTitle>Strategic Business Development</SkillTitle>
          <SkillList>
            <SkillItem>Go-to-Market Strategy &amp; Execution</SkillItem>
            <SkillItem>Partnership Development &amp; Negotiation</SkillItem>
            <SkillItem>Market Entry &amp; Expansion</SkillItem>
            <SkillItem>Stakeholder &amp; Client Relationship Management</SkillItem>
            <SkillItem>Commercial Roadmap Development</SkillItem>
          </SkillList>
        </SkillCategory>

        <SkillCategory>
          <SkillTitle>AI, Machine Learning &amp; Digital Transformation</SkillTitle>
          <SkillList>
            <SkillItem>Computer Vision &amp; AI/ML Solutions</SkillItem>
            <SkillItem>Digital Transformation Initiatives</SkillItem>
            <SkillItem>IoT &amp; Smart Connected Systems</SkillItem>
            <SkillItem>MLOps &amp; AI Model Deployment</SkillItem>
            <SkillItem>Data-Driven Decision Making</SkillItem>
          </SkillList>
        </SkillCategory>

        <SkillCategory>
          <SkillTitle>ESG, Circularity &amp; Sustainability</SkillTitle>
          <SkillList>
            <SkillItem>ESG Strategy &amp; Implementation</SkillItem>
            <SkillItem>Circular Economy Initiatives</SkillItem>
            <SkillItem>Digital Battery Passport Projects</SkillItem>
            <SkillItem>Sustainable Innovation in Automotive &amp; Energy</SkillItem>
            <SkillItem>Regulatory Compliance &amp; Reporting</SkillItem>
          </SkillList>
        </SkillCategory>
      </SkillsGrid>
    </Section>
  </Container>
);

export default About;
